import { useEffect, useRef } from 'react';

export default function ShpeHatAnimation({ onComplete, speed = 1 }) {
  const hatWrapRef = useRef(null);
  const hatImgRef = useRef(null);
  const canvasRef = useRef(null);
  const sceneRef = useRef(null);
  const wrapperRef = useRef(null);

  useEffect(() => {
    function scaleScene() {
      const scene = sceneRef.current;
      const wrapper = wrapperRef.current;
      if (!scene || !wrapper) return;
      const scale = Math.min(1.4, wrapper.clientWidth / 850);
      scene.style.transform = `scale(${scale})`;
      wrapper.style.height = `${300 * scale}px`;
    }
    scaleScene();
    window.addEventListener('resize', scaleScene);
    return () => window.removeEventListener('resize', scaleScene);
  }, []);

  useEffect(() => {
    const hatWrap = hatWrapRef.current;
    const hatImg = hatImgRef.current;
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    const SCENE_W = 850, SCENE_H = 300;
    const HAT_W = 170, HAT_H = 143;

    const HAT_FINAL_X = 58;
    const HAT_REST_X  = 42;
    const HAT_FINAL_Y = 97;

    const HAT_START_X = (SCENE_W - HAT_W) / 2;
    const HAT_START_Y = -HAT_H - 30;

    const STR_OFFSET = 25;
    const LAND_ROT   = 20;
    const FINAL_TILT = 8;

    let animId = null, startTime = null;

    function easeInQuart(t) { return t * t * t * t; }
    function easeOutElastic(t) {
      if (t === 0 || t === 1) return t;
      return Math.pow(2, -10 * t) * Math.sin((t * 10 - 0.75) * (2 * Math.PI / 3.5)) + 1;
    }
    function easeInOutSine(t) { return -(Math.cos(Math.PI * t) - 1) / 2; }
    function easeOutCubic(t) { return 1 - Math.pow(1 - t, 3); }
    function easeOutBounce(t) {
      const n1 = 7.5625, d1 = 2.75;
      if (t < 1/d1) return n1*t*t;
      if (t < 2/d1) { t -= 1.5/d1; return n1*t*t + 0.75; }
      if (t < 2.5/d1) { t -= 2.25/d1; return n1*t*t + 0.9375; }
      t -= 2.625/d1; return n1*t*t + 0.984375;
    }
    function lerp(a, b, t) { return a + (b - a) * t; }

    function drawStrings(hatCX, hatTopY, alpha) {
      if (alpha <= 0) return;
      ctx.save();
      ctx.globalAlpha = alpha;
      ctx.strokeStyle = '#aaa';
      ctx.lineWidth = 1.5;
      ctx.setLineDash([5, 5]);
      ctx.lineCap = 'round';
      ctx.beginPath();
      ctx.moveTo(hatCX - STR_OFFSET, 0);
      ctx.lineTo(hatCX - STR_OFFSET, hatTopY);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(hatCX + STR_OFFSET, 0);
      ctx.lineTo(hatCX + STR_OFFSET, hatTopY);
      ctx.stroke();
      ctx.restore();
    }

    const TOTAL = 5000 / speed;

    function animate(ts) {
      if (!startTime) startTime = ts;
      const raw = Math.min((ts - startTime) / TOTAL, 1);

      ctx.clearRect(0, 0, SCENE_W, SCENE_H);
      let x, y, rot, strAlpha;

      if (raw < 0.10) {
        const pt = raw / 0.10;
        const sway = Math.sin(pt * Math.PI * 2.5) * 20 * (1 - pt * 0.2);
        x = HAT_START_X + sway;
        y = HAT_START_Y + 10 + Math.sin(pt * Math.PI * 1.5) * 5;
        rot = sway * 0.3;
        strAlpha = 1;

      } else if (raw < 0.62) {
        const pt = (raw - 0.10) / 0.52;
        x = lerp(HAT_START_X, HAT_FINAL_X, easeInOutSine(pt));
        y = lerp(HAT_START_Y + 10, HAT_FINAL_Y + 15, easeInQuart(pt));
        rot = lerp(0, LAND_ROT, easeInOutSine(pt));
        strAlpha = Math.max(0, 1 - pt * 2.5);

      } else if (raw < 0.75) {
        const pt = (raw - 0.62) / 0.13;
        x = lerp(HAT_FINAL_X + 4, HAT_FINAL_X, easeOutCubic(pt));
        y = lerp(HAT_FINAL_Y + 15, HAT_FINAL_Y, easeOutElastic(pt));
        rot = lerp(LAND_ROT + 3, LAND_ROT, easeOutCubic(pt));
        strAlpha = 0;

      } else if (raw < 0.82) {
        x = HAT_FINAL_X;
        y = HAT_FINAL_Y;
        rot = LAND_ROT;
        strAlpha = 0;

      } else {
        const pt = (raw - 0.82) / 0.18;
        const riseT = 0.4;
        if (pt < riseT) {
          y = HAT_FINAL_Y - easeOutCubic(pt / riseT) * 38;
        } else {
          y = HAT_FINAL_Y - (1 - easeOutBounce((pt - riseT) / (1 - riseT))) * 38;
        }
        rot = lerp(LAND_ROT, FINAL_TILT, easeInOutSine(pt));
        x   = lerp(HAT_FINAL_X, HAT_REST_X, easeInOutSine(pt));
        strAlpha = 0;
      }

      drawStrings(x + HAT_W / 2, y, strAlpha);
      hatWrap.style.left = x + 'px';
      hatWrap.style.top  = (y || HAT_FINAL_Y) + 'px';
      hatImg.style.transform = `rotate(${rot.toFixed(2)}deg)`;

      if (raw < 1) {
        animId = requestAnimationFrame(animate);
      } else if (onComplete) {
        onComplete();
      }
    }

    startTime = null;
    ctx.clearRect(0, 0, SCENE_W, SCENE_H);
    hatWrap.style.left = HAT_START_X + 'px';
    hatWrap.style.top  = HAT_START_Y + 'px';
    hatImg.style.transform = 'rotate(0deg)';
    setTimeout(() => { animId = requestAnimationFrame(animate); }, 150);

    return () => {
      if (animId) cancelAnimationFrame(animId);
    };
  }, [onComplete, speed]);

  return (
    <>
      <style>{`
        .shpe-scene-wrapper {
          width: min(980px, 90vw);
          overflow: hidden;
          margin: auto;
        }
        .shpe-scene {
          position: relative;
          width: 850px;
          height: 300px;
          overflow: visible;
          transform-origin: top left;
          flex-shrink: 0;
        }
        .shpe-logo-img {
          position: absolute;
          bottom: 0;
          left: 50%;
          transform: translateX(-50%);
          width: 750px;
          height: auto;
        }
        .shpe-hat-wrap {
          position: absolute;
          width: 170px;
        }
        .shpe-string-canvas {
          position: absolute;
          top: 0; left: 0;
          width: 850px;
          height: 300px;
          pointer-events: none;
        }
        .shpe-hat-img {
          width: 170px;
          height: auto;
          display: block;
          transform-origin: center top;
        }
      `}</style>
      <div className="shpe-scene-wrapper" ref={wrapperRef}>
        <div className="shpe-scene" ref={sceneRef}>
          <canvas ref={canvasRef} className="shpe-string-canvas" width="850" height="300"></canvas>
          <img
            className="shpe-logo-img"
            src="data:image/png;base64,"
            alt="SHPE Austin logo"
          />
          <div ref={hatWrapRef} className="shpe-hat-wrap">
            <img
              ref={hatImgRef}
              className="shpe-hat-img"
              src="data:image/png;base64,"
              alt="Cowboy hat"
            />
          </div>
        </div>
      </div>
    </>
  );
}
